  ('Moong Dal Chilla', 'moong-dal-chilla', 'breakfast', 'gujarati', '[{"name": "split moong dal", "quantity": "1/2 cup", "category": "pulses"}, {"name": "ginger", "quantity": "1/2 inch", "category": "vegetables"}, {"name": "green chili", "quantity": "1", "category": "vegetables"}, {"name": "cumin seeds", "quantity": "1/2 tsp", "category": "spices"}, {"name": "oil", "quantity": "1 tsp", "category": "condiments"}]'::jsonb, array['Soak moong dal 4 hours, grind to smooth batter with ginger and chili', 'Add cumin and salt, mix well', 'Pour thin layer on hot tawa, cook both sides with a few drops of oil until golden'], 220, 14, 24, 6, 5, 10, 10, true, 240, true, true, true, true, true, 'mild', array['all'], array['high-protein', 'gluten-free-option']),
